#include <bits/stdc++.h>
using namespace std;

long long merge_count(vector<int>& arr, int l, int r) {
    if (r - l <= 1) return 0;
    int mid = (l + r) / 2;
    long long inv = 0;
    inv += merge_count(arr, l, mid);
    inv += merge_count(arr, mid, r);

    // Merge step: count cross-inversions
    vector<int> tmp;
    int i = l, j = mid;
    while (i < mid && j < r) {
        if (arr[i] <= arr[j]) {
            tmp.push_back(arr[i++]);
        } else {
            // arr[i..mid-1] are all > arr[j] (since left is sorted)
            inv += (mid - i);
            tmp.push_back(arr[j++]);
        }
    }
    while (i < mid) tmp.push_back(arr[i++]);
    while (j < r)   tmp.push_back(arr[j++]);
    for (int k = l; k < r; k++) arr[k] = tmp[k - l];
    return inv;
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (auto& x : arr) cin >> x;

    long long ans = merge_count(arr, 0, n);
    cout << "Inversions: " << ans << "\n";
    cout << "Sorted: ";
    for (int x : arr) cout << x << " ";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Sort pairs by first element (key in range [0, maxVal])
void counting_sort(vector<pair<int,int>>& arr, int maxVal) {
    int n = arr.size();
    vector<int> cnt(maxVal + 1, 0);

    // Step 1: frequency count
    for (auto& p : arr) cnt[p.first]++;

    // Step 2: prefix sum → starting positions
    for (int i = 1; i <= maxVal; i++) cnt[i] += cnt[i-1];

    // Step 3: place in output (traverse BACKWARDS for stability)
    vector<pair<int,int>> out(n);
    for (int i = n - 1; i >= 0; i--) {
        out[--cnt[arr[i].first]] = arr[i];
    }
    arr = out;
}

int main() {
    int n;
    cin >> n;
    vector<pair<int,int>> arr(n);
    for (int i = 0; i < n; i++) {
        cin >> arr[i].first;
        arr[i].second = i; // remember original index
    }

    counting_sort(arr, 1000000);

    for (auto& [val, idx] : arr)
        cout << val << " (orig idx " << idx << ")\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

struct Event {
    int time, type; // type: 0=end, 1=start
    int id;
};

int main() {
    // Pattern 1: Sort pairs — by second desc, then first asc
    vector<pair<int,int>> vp = {{3,5},{1,5},{2,3},{4,1}};
    sort(vp.begin(), vp.end(), [](auto& a, auto& b) {
        if (a.second != b.second) return a.second > b.second; // desc by second
        return a.first < b.first;  // asc by first as tiebreak
    });
    // Result: {1,5},{3,5},{2,3},{4,1}

    // Pattern 2: Sort structs (interval scheduling: end time asc)
    vector<Event> events = {{5,1,0},{3,0,1},{5,0,2},{1,1,3}};
    sort(events.begin(), events.end(), [](const Event& a, const Event& b) {
        if (a.time != b.time) return a.time < b.time;
        return a.type < b.type; // ends (0) before starts (1) at same time
    });

    // Pattern 3: Indirect sort — sort indices by arr values
    vector<int> arr = {40, 10, 30, 20};
    vector<int> idx(arr.size());
    iota(idx.begin(), idx.end(), 0); // idx = {0,1,2,3}
    sort(idx.begin(), idx.end(), [&](int a, int b) {
        return arr[a] < arr[b];
    });
    // idx = {1,3,2,0} — sorted order of positions

    // Pattern 4: Sort strings by length, then lexicographically
    vector<string> words = {"banana", "apple", "kiwi", "fig"};
    sort(words.begin(), words.end(), [](const string& a, const string& b) {
        if (a.size() != b.size()) return a.size() < b.size();
        return a < b;
    });
    // Result: fig, kiwi, apple, banana

    for (auto& w : words) cout << w << " ";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (auto& x : arr) cin >> x;

    // Build compressed mapping
    vector<int> sorted_unique = arr;
    sort(sorted_unique.begin(), sorted_unique.end());
    sorted_unique.erase(unique(sorted_unique.begin(), sorted_unique.end()),
                        sorted_unique.end());

    // Compress: map each value to its rank in [0, m-1]
    auto compress = [&](int val) {
        return (int)(lower_bound(sorted_unique.begin(), sorted_unique.end(), val)
                     - sorted_unique.begin());
    };

    vector<int> comp(n);
    for (int i = 0; i < n; i++) comp[i] = compress(arr[i]);

    // Now values in comp are in [0, m-1] where m = sorted_unique.size()
    int m = sorted_unique.size();
    cout << "Compressed size: " << m << "\n";
    for (int x : comp) cout << x << " ";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    vector<int> arr = {7, 2, 9, 1, 5, 8, 3, 6, 4};
    int k = 3; // want the 3rd smallest (0-indexed: position 2)

    // nth_element: O(n) average — only guarantees position k is correct
    vector<int> a = arr;
    nth_element(a.begin(), a.begin() + k, a.end());
    cout << "3rd smallest: " << a[k] << "\n"; // = 3
    // Elements before a[k] are <= a[k], after are >= a[k] (unordered)

    // partial_sort: O(n log k) — fully sorts first k elements
    vector<int> b = arr;
    partial_sort(b.begin(), b.begin() + k + 1, b.end());
    cout << "Sorted top " << k+1 << ": ";
    for (int i = 0; i <= k; i++) cout << b[i] << " "; // 1 2 3
    cout << "\n";

    // Kth largest using nth_element (reverse)
    vector<int> c = arr;
    nth_element(c.begin(), c.begin() + k, c.end(), greater<int>());
    cout << "3rd largest: " << c[k] << "\n"; // = 7

    return 0;
}

