#include <bits/stdc++.h>
using namespace std;

long long merge_count(vector<int>& a, int l, int r) {
    if (r - l <= 1) return 0;
    int mid = (l + r) / 2;
    long long inv = merge_count(a, l, mid) + merge_count(a, mid, r);
    vector<int> tmp;
    int i = l, j = mid;
    while (i < mid && j < r) {
        if (a[i] <= a[j]) {
            tmp.push_back(a[i++]);
        } else {
            inv += (mid - i); // all of a[i..mid-1] > a[j]
            tmp.push_back(a[j++]);
        }
    }
    while (i < mid) tmp.push_back(a[i++]);
    while (j < r)   tmp.push_back(a[j++]);
    for (int k = l; k < r; k++) a[k] = tmp[k - l];
    return inv;
}

int main() {
    int n; cin >> n;
    vector<int> a(n);
    for (auto& x : a) cin >> x;
    cout << merge_count(a, 0, n) << "\n";
    return 0;
}

