// Given n train arrival and departure times, find the minimum number
// of platforms required so no train waits.
// Input: n, then n arrival times, then n departure times (all integers)
// Output: minimum platforms needed
// Constraints: n <= 10^5, 1 <= arrival[i] <= departure[i] <= 10^4
// Example: arrivals={900,940,950,1100,1500,1800}
//          departures={910,1200,1120,1130,1900,2000} -> 3

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n; cin >> n;
    vector<int> arr(n), dep(n);
    for (auto& x : arr) cin >> x;
    for (auto& x : dep) cin >> x;

    sort(arr.begin(), arr.end());
    sort(dep.begin(), dep.end());

    int platforms = 1, maxPlat = 1;
    int i = 1, j = 0;
    while (i < n && j < n) {
        if (arr[i] <= dep[j]) {
            platforms++;
            i++;
        } else {
            platforms--;
            j++;
        }
        maxPlat = max(maxPlat, platforms);
    }
    cout << maxPlat << "\n";
    return 0;
}

