// You are given n elements and told that after sorting them,
// position p[i] in the sorted array came from position i in the original.
// Given the original array, output: for each original index, its rank (1-indexed).
// Input: n integers
// Output: their ranks after sorting (1-based, handle duplicates by original index)
// Example: input 40 10 30 20 -> output 4 1 3 2

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n; cin >> n;
    vector<int> arr(n);
    for (auto& x : arr) cin >> x;

    vector<int> idx(n);
    iota(idx.begin(), idx.end(), 0);
    // Stable sort: ties broken by original position (ascending idx)
    stable_sort(idx.begin(), idx.end(), [&](int a, int b) {
        return arr[a] < arr[b];
    });

    // rank[original_position] = rank (1-indexed)
    vector<int> rank_(n);
    for (int i = 0; i < n; i++) rank_[idx[i]] = i + 1;

    for (int r : rank_) cout << r << " ";
    cout << "\n";
    return 0;
}
